import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatDate, formatVnd } from '../../../utils/formatters';
import { monthStartEnd } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type {
  PartnerDto,
  ReceivablePayableDetailRow,
  ReceivablePayableSummaryRow,
} from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTabBar, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-cong-no';
const PAGE_ID = 'baocao-cong-no';
const DEBT_OPTIONS = [
  { value: '', label: 'Tất cả' },
  { value: 'Receivable', label: 'Phải thu' },
  { value: 'Payable', label: 'Phải trả' },
];

const BaoCaoCongNoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { fromDate: iF, toDate: iT } = monthStartEnd();
  const [fromDate, setFromDate] = useState(iF);
  const [toDate, setToDate] = useState(iT);
  const [tab, setTab] = useState<'summary' | 'detail'>('summary');
  const [debtType, setDebtType] = useState('');
  const [partnerId, setPartnerId] = useState('');
  const [detailPartnerId, setDetailPartnerId] = useState('');
  const [partners, setPartners] = useState<PartnerDto[]>([]);
  const [summary, setSummary] = useState<ReceivablePayableSummaryRow[]>([]);
  const [detail, setDetail] = useState<ReceivablePayableDetailRow[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      analyticsService
        .getPartners({ pageSize: 500 })
        .then(d => {
          if (!cancelled) setPartners(d);
        })
        .catch(() => {});
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, []);

  const handleLoad = useCallback(() => {
    if (tab === 'detail' && !detailPartnerId) {
      dispatchAppToast(dispatch, {
        message: 'Chọn đối tác cho tab Chi tiết',
        type: 'warning',
      });
      return;
    }
    setLoading(true);
    const p = { fromDate, toDate, debtType: debtType || undefined, partnerId: partnerId || undefined };
    const req =
      tab === 'summary'
        ? analyticsService.getReceivablePayableSummary(p)
        : analyticsService.getReceivablePayableDetail({ ...p, partnerId: detailPartnerId });
    req
      .then(d => {
        if (tab === 'summary') setSummary(d as ReceivablePayableSummaryRow[]);
        else setDetail(d as ReceivablePayableDetailRow[]);
      })
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [tab, fromDate, toDate, debtType, partnerId, detailPartnerId, dispatch]);

  const rows = tab === 'summary' ? summary : detail;

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          setFromDate(from ?? '');
          setToDate(to ?? '');
        }}
        dateLabel="Thời gian"
        expandDateRangeAriaLabel="Thêm ngày kết thúc"
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-debt`}>
              <Select
                label="Loại"
                value={debtType}
                onChange={e => setDebtType(e.target.value)}
                options={DEBT_OPTIONS}
                size="small"
              />
            </div>
            <div data-testid={`${TEST_ID}-field-partner`}>
              <Select
                label={tab === 'summary' ? 'Đối tượng' : 'Đối tác (chi tiết)'}
                value={tab === 'summary' ? partnerId : detailPartnerId}
                onChange={e =>
                  tab === 'summary' ? setPartnerId(e.target.value) : setDetailPartnerId(e.target.value)
                }
                options={[
                  { value: '', label: tab === 'summary' ? 'Tất cả ĐT' : 'Chọn đối tác' },
                  ...partners.map(p => ({ value: p.id, label: p.name })),
                ]}
                size="small"
              />
            </div>
          </>
        )}
      />
    ),
    [fromDate, toDate, debtType, tab, partnerId, detailPartnerId, partners, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo công nợ"
      titleIconClass="fas fa-balance-scale"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath={
        tab === 'summary'
          ? '/accounting/receivable-payable/summary/export-excel'
          : '/accounting/receivable-payable/detail/export-excel'
      }
      exportParams={{
        fromDate,
        toDate,
        debtType: debtType || undefined,
        partnerId: (tab === 'summary' ? partnerId : detailPartnerId) || undefined,
      }}
      exportFilename={`CongNo-${fromDate}.xlsx`}
      tabBar={
        <ReportTabBar
          testId={TEST_ID}
          tabs={[
            { id: 'summary', label: 'Tổng hợp' },
            { id: 'detail', label: 'Chi tiết' },
          ]}
          activeId={tab}
          onChange={id => setTab(id as 'summary' | 'detail')}
        />
      }
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            {tab === 'summary' ? (
              <>
                <th>Mã ĐT</th>
                <th>Tên</th>
                <th>TK</th>
                <th className={reportStyles.colRight}>Dư Nợ ĐK</th>
                <th className={reportStyles.colRight}>Dư Có ĐK</th>
                <th className={reportStyles.colRight}>PS Nợ</th>
                <th className={reportStyles.colRight}>PS Có</th>
                <th className={reportStyles.colRight}>Dư Nợ CK</th>
                <th className={reportStyles.colRight}>Dư Có CK</th>
              </>
            ) : (
              <>
                <th>Ngày</th>
                <th>Số CT</th>
                <th>Loại</th>
                <th>Diễn giải</th>
                <th className={reportStyles.colRight}>Nợ</th>
                <th className={reportStyles.colRight}>Có</th>
                <th className={reportStyles.colRight}>Số dư</th>
              </>
            )}
          </tr>
        </thead>
        <tbody>
          {tab === 'summary'
            ? summary.map((r, i) => (
                <tr key={i}>
                  <td>{r.partnerCode}</td>
                  <td>{r.partnerName}</td>
                  <td>{r.accountCode}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.openingDebit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.openingCredit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.arisingDebit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.arisingCredit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.closingDebit)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.closingCredit)}</td>
                </tr>
              ))
            : detail.map((r, i) => (
                <tr key={i}>
                  <td>{formatDate(r.voucherDate)}</td>
                  <td>{r.voucherNumber}</td>
                  <td>{r.voucherType}</td>
                  <td>{r.description}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.debitAmount)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.creditAmount)}</td>
                  <td className={reportStyles.colRight}>{formatVnd(r.balance)}</td>
                </tr>
              ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoCongNoPage;
